124	pub enum StreamEvent {
125	    Token(String),
126	    /// Reasoning/thinking text from a separate provider field. Distinct from
127	    /// `Token` so the UI can render it differently. For inline `<think>` tags
128	    /// inside content, the UI parses the assembled text itself.
129	    Reasoning(String),
130	    /// The complete list of tool calls the model emitted in this turn,
131	    /// assembled from per-chunk deltas. Sent before `Done` if any tool
132	    /// calls happened. The app assigns these to the streaming assistant
133	    /// message, then runs them after `Done`.
134	    ToolCalls(Vec<ToolCall>),
135	    Done,
136	    Error(String),
137	    UsageInfo(Usage),
138	    /// `url` is the endpoint the fetch was started against. The receiver
139	    /// validates it still matches the currently-selected endpoint before
140	    /// applying — without that check, switching endpoints while a fetch is
141	    /// in flight could populate the new endpoint with the old endpoint's
142	    /// model list.
143	    ModelsLoaded {
144	        url: String,
145	        models: Vec<String>,
146	    },
147	}
