152	pub async fn fetch_models(base_url: &str, api_key: Option<&str>) -> Result<Vec<String>, String> {
153	    let client = Client::builder()
154	        .timeout(REQUEST_TIMEOUT)
155	        .connect_timeout(CONNECT_TIMEOUT)
156	        .build()
157	        .map_err(|e| format!("Failed to create HTTP client: {e}"))?;
158	
159	    let mut url = base_url.trim_end_matches('/').to_string();
160	
161	    // Auto-fix OpenRouter URLs (users often provide just the domain or the
162	    // completions endpoint). Only rewrite when the URL's host is literally
163	    // openrouter.ai — substring matching would let `evil.com/openrouter.ai`
164	    // hijack the rewrite and leak the bearer token.
165	    let is_openrouter = host_is(&url, "openrouter.ai");
166	    if is_openrouter {
167	        url = "https://openrouter.ai/api/v1".to_string();
168	    } else if url.ends_with("/chat/completions") {
169	        url = url.trim_end_matches("/chat/completions").to_string();
170	    }
171	
172	    // Try OpenAI-standard /v1/models first (works for OpenRouter, LM Studio, vLLM, etc.)
173	    let models_url = if url.ends_with("/v1") {
174	        format!("{url}/models")
175	    } else {
176	        format!("{url}/v1/models")
177	    };
178	
179	    let mut request = client.get(&models_url);
180	    if let Some(key) = api_key {
181	        request = request.bearer_auth(key);
182	    }
183	    if is_openrouter {
184	        request = request
185	            .header("HTTP-Referer", "https://github.com/hhheath/hChat")
186	            .header("X-Title", "hChat");
187	    }
188	
189	    if let Ok(resp) = request.send().await {
190	        if resp.status().is_success() {
191	            if let Ok(openai_resp) = resp.json::<OpenAIModelsResponse>().await {
192	                let models: Vec<String> = openai_resp.data.into_iter().map(|m| m.id).collect();
193	                if !models.is_empty() {
194	                    return Ok(models);
195	                }
196	            }
197	        }
198	    }
199	
200	    // Fall back to Ollama /api/tags
201	    let api_base = url.trim_end_matches("/v1");
202	    let resp = client
203	        .get(format!("{api_base}/api/tags"))
204	        .send()
205	        .await
206	        .map_err(|e| format!("Failed to fetch models: {e}"))?;
207	
208	    let tags: OllamaTagsResponse = resp
209	        .json()
210	        .await
211	        .map_err(|e| format!("Failed to parse models: {e}"))?;
212	
213	    Ok(tags.models.into_iter().map(|m| m.name).collect())
214	}
