231	pub fn stream_chat(
232	    params: ChatParams,
233	    tx: mpsc::UnboundedSender<StreamEvent>,
234	    cancel: CancellationToken,
235	) {
236	    tokio::spawn(async move {
237	        let ChatParams {
238	            base_url,
239	            model,
240	            messages,
241	            temperature,
242	            max_tokens,
243	            top_p,
244	            frequency_penalty,
245	            presence_penalty,
246	            stop_sequences,
247	            api_key,
248	            tools,
249	        } = params;
250	        let client = match Client::builder().connect_timeout(CONNECT_TIMEOUT).build() {
251	            Ok(c) => c,
252	            Err(e) => {
253	                let _ = tx.send(StreamEvent::Error(format!(
254	                    "Failed to create HTTP client: {e}"
255	                )));
256	                return;
257	            }
258	        };
259	        let mut base_url = base_url.trim_end_matches('/').to_string();
260	
261	        let is_openrouter = host_is(&base_url, "openrouter.ai");
262	        if is_openrouter {
263	            base_url = "https://openrouter.ai/api/v1".to_string();
264	        } else if base_url.ends_with("/chat/completions") {
265	            base_url = base_url.trim_end_matches("/chat/completions").to_string();
266	        }
267	
268	        let url = format!("{}/chat/completions", base_url);
269	
270	        let req = ChatRequest {
271	            model,
272	            messages,
273	            stream: true,
274	            temperature,
275	            max_tokens,
276	            top_p,
277	            frequency_penalty,
278	            presence_penalty,
279	            stop_sequences,
280	            tools,
281	        };
282	
283	        let mut request = client.post(&url).json(&req);
284	        if let Some(key) = &api_key {
285	            request = request.bearer_auth(key);
286	        }
287	        if is_openrouter {
288	            request = request
289	                .header("HTTP-Referer", "https://github.com/hhheath/hChat")
290	                .header("X-Title", "hChat");
291	        }
292	
293	        let resp = match request.send().await {
294	            Ok(r) => r,
295	            Err(e) => {
296	                let _ = tx.send(StreamEvent::Error(format!("Request failed: {e}")));
297	                return;
298	            }
299	        };
300	
301	        if !resp.status().is_success() {
302	            let status = resp.status();
303	            let body = resp
304	                .bytes()
305	                .await
306	                .map(|b| {
307	                    let truncated = &b[..b.len().min(MAX_ERROR_BODY)];
308	                    String::from_utf8_lossy(truncated).into_owned()
309	                })
310	                .unwrap_or_default();
311	            // Log full error for debugging but only show sanitized message in UI
312	            eprintln!("API error {status}: {body}");
313	            let message = match status.as_u16() {
314	                401 => format!("{status}: Authentication failed — check your API key"),
315	                403 => format!("{status}: Access denied"),
316	                404 => format!("{status}: Endpoint not found — check your URL"),
317	                429 => format!("{status}: Rate limited — try again later"),
318	                500..=599 => format!("{status}: Server error"),
319	                _ => format!("{status}: Request failed"),
320	            };
321	            let _ = tx.send(StreamEvent::Error(message));
322	            return;
323	        }
324	
325	        let mut stream = resp.bytes_stream();
326	        // Use a byte buffer to handle UTF-8 sequences split across chunks
327	        let mut raw_buf: Vec<u8> = Vec::new();
328	
329	        // Tool call accumulator: index → (id, name, arguments-so-far). We
330	        // assemble per-slot across deltas and emit a single ToolCalls event
331	        // before Done. Using a Vec<Option<_>> keyed by index handles sparse
332	        // / out-of-order deltas without allocating a HashMap for what's
333	        // typically 1–3 calls.
334	        let mut tool_acc: Vec<Option<(Option<String>, String, String)>> = Vec::new();
335	
336	        loop {
337	            tokio::select! {
338	                _ = cancel.cancelled() => {
339	                    flush_tool_calls(&mut tool_acc, &tx);
340	                    let _ = tx.send(StreamEvent::Done);
341	                    return;
342	                }
343	                chunk = stream.next() => {
344	                    let Some(chunk) = chunk else {
345	                        flush_tool_calls(&mut tool_acc, &tx);
346	                        let _ = tx.send(StreamEvent::Done);
347	                        return;
348	                    };
349	
350	                    let bytes = match chunk {
351	                        Ok(b) => b,
352	                        Err(e) => {
353	                            let _ = tx.send(StreamEvent::Error(format!("Stream error: {e}")));
354	                            return;
355	                        }
356	                    };
357	
358	                    if raw_buf.len() + bytes.len() > MAX_STREAM_BUFFER {
359	                        let _ = tx.send(StreamEvent::Error("Stream buffer overflow".to_string()));
360	                        return;
361	                    }
362	
363	                    raw_buf.extend_from_slice(&bytes);
364	
365	                    // Find the last valid UTF-8 boundary to avoid splitting multi-byte chars
366	                    let valid_up_to = match std::str::from_utf8(&raw_buf) {
367	                        Ok(_) => raw_buf.len(),
368	                        Err(e) => e.valid_up_to(),
369	                    };
370	
371	                    if valid_up_to == 0 {
372	                        continue;
373	                    }
374	
375	                    // Safe: we just validated this range is valid UTF-8
376	                    let text = std::str::from_utf8(&raw_buf[..valid_up_to]).unwrap();
377	                    let mut remaining_start = 0;
378	
379	                    for line_end in newline_positions(text) {
380	                        let line = text[remaining_start..line_end].trim();
381	                        remaining_start = line_end + 1;
382	
383	                        if line.is_empty() || line.starts_with(':') {
384	                            continue;
385	                        }
386	
387	                        let data = if let Some(d) = line.strip_prefix("data: ") {
388	                            d.trim()
389	                        } else {
390	                            continue;
391	                        };
392	
393	                        if data == "[DONE]" {
394	                            flush_tool_calls(&mut tool_acc, &tx);
395	                            let _ = tx.send(StreamEvent::Done);
396	                            return;
397	                        }
398	
399	                        if let Ok(chunk) = serde_json::from_str::<ChatChunk>(data) {
400	                            if let Some(choices) = chunk.choices {
401	                                for choice in choices {
402	                                    if let Some(delta) = choice.delta {
403	                                        // Skip empty strings: some providers
404	                                        // (Ollama qwen3 thinking, OpenAI keep-
405	                                        // alives) emit `content: ""` alongside
406	                                        // a reasoning delta. Treating that as
407	                                        // "content arrived" prematurely closes
408	                                        // the <think> block and the next
409	                                        // reasoning delta re-opens a new one,
410	                                        // producing dozens of tiny blocks.
411	                                        if let Some(reasoning) = delta.reasoning
412	                                            && !reasoning.is_empty()
413	                                        {
414	                                            let _ = tx.send(StreamEvent::Reasoning(reasoning));
415	                                        }
416	                                        if let Some(content) = delta.content
417	                                            && !content.is_empty()
418	                                        {
419	                                            let _ = tx.send(StreamEvent::Token(content));
420	                                        }
421	                                        if let Some(tcds) = delta.tool_calls {
422	                                            for tcd in tcds {
423	                                                accumulate_tool_call(&mut tool_acc, tcd);
424	                                            }
425	                                        }
426	                                    }
427	                                }
428	                            }
429	                            if let Some(usage) = chunk.usage {
430	                                let _ = tx.send(StreamEvent::UsageInfo(usage));
431	                            }
432	                        }
433	                    }
434	
435	                    // Keep unprocessed bytes (incomplete line + any trailing invalid UTF-8)
436	                    let consumed = remaining_start.min(valid_up_to);
437	                    raw_buf = raw_buf[consumed..].to_vec();
438	                }
439	            }
440	        }
441	    });
442	}
