444	/// Append a streaming `ToolCallDelta` into the accumulator. The accumulator
445	/// is keyed by the slot `index` so out-of-order deltas across chunks land
446	/// in the right slot. `id` and `name` arrive once each (usually in the
447	/// first delta for a slot); `arguments` is concatenated piecewise.
448	fn accumulate_tool_call(
449	    acc: &mut Vec<Option<(Option<String>, String, String)>>,
450	    d: ToolCallDelta,
451	) {
452	    while acc.len() <= d.index {
453	        acc.push(None);
454	    }
455	    let slot = acc[d.index].get_or_insert_with(|| (None, String::new(), String::new()));
456	    if let Some(id) = d.id {
457	        slot.0 = Some(id);
458	    }
459	    if let Some(f) = d.function {
460	        if let Some(name) = f.name {
461	            slot.1 = name;
462	        }
463	        if let Some(args) = f.arguments {
464	            slot.2.push_str(&args);
465	        }
466	    }
467	}
468	
469	/// Drain the accumulator into a final `ToolCalls` event. Slots missing an
470	/// id are dropped (and logged) — without an id we can't match a result
471	/// back. No-op if no calls were accumulated, so emitting unconditionally
472	/// before Done is safe.
473	fn flush_tool_calls(
474	    acc: &mut Vec<Option<(Option<String>, String, String)>>,
475	    tx: &mpsc::UnboundedSender<StreamEvent>,
476	) {
477	    let calls: Vec<ToolCall> = acc
478	        .drain(..)
479	        .enumerate()
480	        .filter_map(|(slot_idx, slot)| {
481	            let (id, name, args) = slot?;
482	            let Some(id) = id else {
483	                // The model thinks it called this tool; we'd be telling it
484	                // nothing came back. Surface a diagnostic so the dropped
485	                // call is at least debuggable.
486	                eprintln!(
487	                    "tool_call slot {slot_idx} ('{name}') arrived without an id — dropping"
488	                );
489	                return None;
490	            };
491	            Some(ToolCall {
492	                id,
493	                call_type: "function".to_string(),
494	                function: ToolCallFunction {
495	                    name,
496	                    arguments: args,
497	                },
498	            })
499	        })
500	        .collect();
501	    if !calls.is_empty() {
502	        let _ = tx.send(StreamEvent::ToolCalls(calls));
503	    }
504	}
