506	/// Find all newline positions in a string slice
507	fn newline_positions(s: &str) -> impl Iterator<Item = usize> + '_ {
508	    s.bytes()
509	        .enumerate()
510	        .filter_map(|(i, b)| if b == b'\n' { Some(i) } else { None })
511	}
