539	/// Single-shot non-streaming chat completion. Used by auto-title (one short
540	/// reply, no streaming UI). Always returns the full assistant message string
541	/// or an error.
542	pub async fn complete_once(
543	    base_url: &str,
544	    model: &str,
545	    messages: &[Message],
546	    api_key: Option<&str>,
547	    max_tokens: Option<u32>,
548	    temperature: Option<f32>,
549	) -> Result<String, String> {
550	    let client = Client::builder()
551	        .timeout(REQUEST_TIMEOUT)
552	        .connect_timeout(CONNECT_TIMEOUT)
553	        .build()
554	        .map_err(|e| format!("Failed to create HTTP client: {e}"))?;
555	
556	    let mut base_url = base_url.trim_end_matches('/').to_string();
557	    let is_openrouter = host_is(&base_url, "openrouter.ai");
558	    if is_openrouter {
559	        base_url = "https://openrouter.ai/api/v1".to_string();
560	    } else if base_url.ends_with("/chat/completions") {
561	        base_url = base_url.trim_end_matches("/chat/completions").to_string();
562	    }
563	    let url = format!("{}/chat/completions", base_url);
564	
565	    let req = NonStreamingChatRequest {
566	        model,
567	        messages,
568	        stream: false,
569	        max_tokens,
570	        temperature,
571	    };
572	
573	    let mut request = client.post(&url).json(&req);
574	    if let Some(key) = api_key {
575	        request = request.bearer_auth(key);
576	    }
577	    if is_openrouter {
578	        request = request
579	            .header("HTTP-Referer", "https://github.com/hhheath/hChat")
580	            .header("X-Title", "hChat");
581	    }
582	
583	    let resp = request
584	        .send()
585	        .await
586	        .map_err(|e| format!("Request failed: {e}"))?;
587	    if !resp.status().is_success() {
588	        let status = resp.status();
589	        return Err(format!("{status}"));
590	    }
591	    let parsed: NonStreamingChatResponse = resp
592	        .json()
593	        .await
594	        .map_err(|e| format!("Failed to parse response: {e}"))?;
595	    parsed
596	        .choices
597	        .into_iter()
598	        .next()
599	        .and_then(|c| c.message.content)
600	        .ok_or_else(|| "Empty response".to_string())
601	}
